starter.javascript:
let height = 45;
// write an IF-ELSE:
//   if height >= 48: print exactly: Board the ride
//   otherwise (else): print exactly: Grow a bit more
// exactly one branch runs

reference.pseudocode:
height ← 45
IF(height ≥ 48)
{
  DISPLAY("Board the ride")
}
ELSE
{
  DISPLAY("Grow a bit more")
}

